class MyLayoutDelegate extends MultiChildLayoutDelegate {
  @override
  void performLayout(Size size) {
    // ID 'header' for top, ID 'content' for bottom
    final headerSize = layoutChild('header', BoxConstraints.tightFor(height: 50));
    positionChild('header', Offset.zero);

    layoutChild('content', BoxConstraints.tightFor(width: size.width));
    positionChild('content', Offset(0, headerSize.height));
  }
  @override
  bool shouldRelayout(covariant MultiChildLayoutDelegate oldDelegate) => false;
}
